import java.util.*;

public class WordCountApp {
    public static void main(String[] args) {
        String text = readLineFromUser();
        int count = countWords(text);
        printReport(text, count);
    }

    private static String readLineFromUser() {
        Scanner sc = new Scanner(System.in);
        System.out.print("Enter a line: ");
        String line = sc.nextLine();
        // sc not closed to avoid closing System.in
        return line;
    }

    private static int countWords(String text) {
        if (text == null || text.trim().isEmpty()) return 0;
        String[] tokens = text.trim().split("\\s+");
        return tokens.length;
    }

    private static void printReport(String text, int count) {
        System.out.println("You entered: " + text);
        System.out.println("Word count: " + count);
    }
}

public class PasswordValidator {
    public static void main(String[] args) {
        System.out.println(isValidPassword("Abcdef12")); // true
        System.out.println(isValidPassword("abcdef12")); // false (no uppercase)
    }

    public static boolean isValidPassword(String pw) {
        return isLongEnough(pw) && hasUpper(pw) && hasDigit(pw);
    }

    private static boolean isLongEnough(String pw) {
        return pw != null && pw.length() >= 8;
    }

    private static boolean hasUpper(String pw) {
        if (pw == null) return false;
        for (char c : pw.toCharArray()) {
            if (Character.isUpperCase(c)) return true;
        }
        return false;
    }

    private static boolean hasDigit(String pw) {
        if (pw == null) return false;
        for (char c : pw.toCharArray()) {
            if (Character.isDigit(c)) return true;
        }
        return false;
    }
}

import java.util.*;

public class PrimeLister {
    public static void main(String[] args) {
        int n = readUpperBound();
        for (int i = 2; i <= n; i++) {
            if (isPrime(i)) {
                System.out.println(i);
            }
        }
    }

    private static int readUpperBound() {
        Scanner sc = new Scanner(System.in);
        System.out.print("List primes up to: ");
        while (!sc.hasNextInt()) {
            System.out.print("Enter a valid integer: ");
            sc.next();
        }
        int n = sc.nextInt();
        return Math.max(n, 0);
    }

    public static boolean isPrime(int k) {
        if (k < 2) return false;
        int limit = (int)Math.sqrt(k);
        for (int d = 2; d <= limit; d++) {
            if (k % d == 0) return false;
        }
        return true;
    }
}
